matching `du -sb` (i.e., st_blocks * 512 for files, directory overhead included).
"""

import os
import sys
import errno


def dir_size(path: str) -> int:
    """Return total disk usage in bytes of all regular files under path."""
    total = 0
    try:
        # Add the directory's own overhead (size of its inode).
        # du -sb includes the directory's own disk usage (typically 4096).
        total += os.stat(path).st_blocks * 512
    except OSError:
        pass

    for dirpath, dirnames, filenames in os.walk(path):
        # For each subdirectory, its overhead is already accounted by os.walk
        # when it becomes the current dirpath; we'll add it inside the loop.
        # But careful not to double‑count the root.
        if dirpath != path:
            try:
                total += os.stat(dirpath).st_blocks * 512
            except OSError:
                pass

        for filename in filenames:
            filepath = os.path.join(dirpath, filename)
            try:
                st = os.stat(filepath)
                if os.path.isfile(filepath):
                    total += st.st_blocks * 512
            except OSError:
                # ignore missing/unreadable files
                continue
    return total


